function solve(s) {
    // 1. Count frequencies of all characters
    const freq = new Map();
    for (const char of s) {
        freq.set(char, (freq.get(char) || 0) + 1);
    }

    // Helper function to get the mirror character
    function getMirrorChar(char) {
        const code = char.charCodeAt(0);

        if (code >= 'a'.charCodeAt(0) && code <= 'z'.charCodeAt(0)) {
            // Letter: 'a' <-> 'z', 'b' <-> 'y', etc.
            // Position from 'a' (0-25) -> 25 - position
            const offset = code - 'a'.charCodeAt(0);
            const mirrorOffset = 25 - offset;
            return String.fromCharCode('a'.charCodeAt(0) + mirrorOffset);
        } else if (code >= '0'.charCodeAt(0) && code <= '9'.charCodeAt(0)) {
            // Digit: '0' <-> '9', '1' <-> '8', etc.
            // Position from '0' (0-9) -> 9 - position
            const offset = code - '0'.charCodeAt(0);
            const mirrorOffset = 9 - offset;
            return String.fromCharCode('0'.charCodeAt(0) + mirrorOffset);
        }
        // Should not happen based on problem constraints
        return null;
    }

    let totalDifferenceSum = 0;
    const processedPairs = new Set();

    // 2. Iterate over unique characters and calculate differences for unique mirror pairs
    for (const char of freq.keys()) {
        if (processedPairs.has(char)) {
            continue;
        }

        const m = getMirrorChar(char);

        if (m === null) {
            // Should not happen
            continue;
        }

        // Determine canonical order to ensure the pair is processed only once
        // We use lexicographical comparison for the pair key
        const pairKey = char < m ? char + '#' + m : m + '#' + char;

        if (processedPairs.has(pairKey)) {
            continue;
        }

        // Calculate frequencies, handling cases where m might not be in freq (freq is 0)
        const freqC = freq.get(char) || 0;
        const freqM = freq.get(m) || 0;

        // Calculate absolute difference
        const diff = Math.abs(freqC - freqM);

        // Add to sum
        totalDifferenceSum += diff;

        // Mark both characters as processed for this pair
        processedPairs.add(pairKey);
    }

    return totalDifferenceSum;
}

